import fs from 'fs';
import { createClient } from '@libsql/client';

async function main() {
  const url = process.env.DATABASE_URL;
  const authToken = process.env.TURSO_AUTH_TOKEN;

  if (!url || !authToken) {
    console.error("Missing DATABASE_URL or TURSO_AUTH_TOKEN in .env");
    process.exit(1);
  }

  console.log("Connecting to Turso...");
  const client = createClient({ url, authToken });

  console.log("Reading schema.sql...");
  // Read UTF-16LE as generated by Powershell/CMD redirection
  let sql = fs.readFileSync('schema.sql', 'utf16le');
  
  // split statements (simple approach based on lines or semicolons)
  // Usually prisma diff gives a few create table statements
  const statements = sql.split(';').map(s => s.trim()).filter(s => s.length > 0);

  for (const stmt of statements) {
    console.log("Executing:", stmt.substring(0, 50) + "...");
    try {
      await client.execute(stmt);
    } catch (e) {
      console.error("Error executing statement:", e.message);
    }
  }

  console.log("Database schema pushed to Turso successfully!");
}

main().catch(console.error);
